  const runtime = el('select', {}, ['transformers', 'vllm', 'sglang', 'llama.cpp', 'cloud', 'auto'].map(x => el('option', { value: x }, x))); runtime.value = settingValueOr('default_model_runtime_engine', 'transformers');
